test-case.copilot-command:
$servers = @("serverA", "serverB", "serverC")
foreach ($srv in $servers) {
    Write-Host "--- $srv ---"
    Get-Service -ComputerName $srv | Where-Object Status -eq "Running" |
        Select-Object Name, Status, StartType | Format-Table -AutoSize
}

$computers = Get-Content "C:\servers.txt"
foreach ($computer in $computers) {
    try {
        $regVal = Get-ItemProperty -Path "HKLM:\SOFTWARE\Microsoft\Windows NT\CurrentVersion" `
            -ComputerName $computer -ErrorAction Stop
        Write-Host "$computer : $($regVal.ProductName)"
    }
    catch [System.UnauthorizedAccessException] {
        Write-Warning "Access denied on $computer"
    }
    catch {
        Write-Warning "Failed to connect to $computer : $_"
    }
}

$service = "W3SVC"
$maxAttempts = 30
$attempt = 0
while ($attempt -lt $maxAttempts) {
    $status = (Get-Service -Name $service).Status
    if ($status -eq "Running") {
        Write-Host "$service is Running!" -ForegroundColor Green
        break
    }
    else {
        Write-Host "Waiting for $service... ($attempt/$maxAttempts)" -ForegroundColor Yellow
        Start-Sleep -Seconds 2
        $attempt++
    }
}
if ($attempt -eq $maxAttempts) {
    Write-Warning "$service did not start within timeout"
}

Get-Process | ForEach-Object {
    $cpu = $_.CPU
    switch ($cpu) {
        {$_ -gt 100} { Write-Host "$($_.Name): HIGH CPU ($cpu sec)" -ForegroundColor Red; break }
        {$_ -gt 50}  { Write-Host "$($_.Name): MODERATE CPU ($cpu sec)" -ForegroundColor Yellow; break }
        {$_ -gt 0}   { Write-Host "$($_.Name): LOW CPU" -ForegroundColor Green; break }
    }
}

Invoke-Command -ComputerName "DC01", "DC02" -ScriptBlock {
    Get-CimInstance -ClassName Win32_LogicalDisk -Filter "DriveType=3" |
        Select-Object DeviceID, VolumeName, @{
            Name='FreeSpaceGB'
            Expression={[math]::Round($_.FreeSpace/1GB, 2)}
        }, @{
            Name='TotalSpaceGB'
            Expression={[math]::Round($_.Size/1GB, 2)}
        } | Format-Table -AutoSize
}

$events = Get-WinEvent -FilterHashtable @{
    LogName='Application'
    Level=2
    StartTime=(Get-Date).AddDays(-7)
} -MaxEvents 50

if ($events) {
    Write-Host "Found $($events.Count) errors in the last 7 days:" -ForegroundColor Red
    $events | Select-Object TimeCreated, ProviderName, Message | Format-List
}
else {
    Write-Host "No application errors found." -ForegroundColor Green
}

$services = Get-Service -Name "App_*" | Where-Object Status -eq "Running"
foreach ($svc in $services) {
    Write-Host "Stopping $($svc.Name)..." -ForegroundColor Yellow
    try {
        Stop-Service -Name $svc.Name -Force -ErrorAction Stop
        Write-Host "  Stopped successfully." -ForegroundColor Green
    }
    catch {
        Write-Warning "Failed to stop $($svc.Name): $_"
    }
}

Invoke-Command -ComputerName (Get-Content "C:\serverlist.txt") -ScriptBlock {
    $packagePath = "\\fileserver\installs\app.msi"
    if (Test-Path $packagePath) {
        Start-Process -FilePath "msiexec.exe" -ArgumentList "/i `"$packagePath`" /qn /norestart" -Wait
        Write-Host "Package installed on $env:COMPUTERNAME" -ForegroundColor Green
    }
    else {
        Write-Warning "Package not found at $packagePath"
    }
}

$deployPath = "C:\inetpub\wwwroot\app" $backupPath = "C:\backups\app_$(Get-Date -Format 'yyyyMMdd_HHmmss')" try { # Create backup first Copy-Item -Path $deployPath -Destination $backupPath -Recurse -Force Write-Host "Backup created at $backupPath" -ForegroundColor Green
# Remove old deployment Remove-Item -Path "$deployPath\*" -Recurse -Force
# Deploy new files Copy-Item -Path "C:\builds\app_latest\*" -Destination $deployPath -Recurse -Force Write-Host "Deployment complete." -ForegroundColor Green } catch { Write-Warning "Deployment failed! Rolling back..." Remove-Item -Path "$deployPath\*" -Recurse -Force Copy-Item -Path "$backupPath\*" -Destination $deployPath -Recurse -Force Write-Host "Rollback complete." -ForegroundColor Yellow } finally { Restart-Service -Name "W3SVC" Write-Host "IIS restarted." -ForegroundColor Cyan }

$logDir = "C:\logs"
$cutoffDate = (Get-Date).AddDays(-30)
$deletedCount = 0

$files = Get-ChildItem -Path $logDir -Filter "*.log" |
    Where-Object CreationTime -lt $cutoffDate

foreach ($f in $files) {
    if ($f.LastWriteTime -lt $cutoffDate) {
        Remove-Item $f.FullName -Force
        $deletedCount++
        Write-Host "Deleted: $($f.Name)" -ForegroundColor DarkGray
    }
}
Write-Host "Total cleaned up: $deletedCount files" -ForegroundColor Green

Invoke-Command -ComputerName "SRV01", "SRV02" -ScriptBlock {
    net stop "AppService" /y
    Write-Host "Service stopped on $env:COMPUTERNAME"
}

Invoke-Command -ComputerName "WEB01", "WEB02", "WEB03" -ScriptBlock {
    Get-WmiObject -Class Win32_LogicalDisk -Filter "DriveType=3" |
        Select-Object SystemName, DeviceID, @{N='FreeGB';E={[math]::Round($_.FreeSpace/1GB,2)}}, @{N='UsedGB';E={[math]::Round(($_.Size-$_.FreeSpace)/1GB,2)}}
} | Format-Table -AutoSize

Invoke-Command -ComputerName (Get-Content C:\servers.txt) -ScriptBlock {
    Set-Service -Name "Telnet" -StartupType Disabled -Status Stopped
    Write-Host "Telnet disabled on $env:COMPUTERNAME"
}

for line in $(tail -20 /var/log/syslog); do
    case "$line" in
        *"error"*|*"ERROR"*)   echo "[CRITICAL] $line" ;;
        *"warning"*|*"WARN"*)  echo "[WARNING]  $line" ;;
        *"info"*|*"INFO"*)     echo "[INFO]     $line" ;;
        *)                     echo "[DEBUG]    $line" ;;
    esac
done

install_package() { local pkg="$1" if dpkg -l "$pkg" > /dev/null 2>&1; then echo "$pkg is already installed, skipping..." return 0 fi
echo "Installing $pkg..." if apt-get install -y "$pkg"; then echo "$pkg installed successfully." else echo "ERROR: Failed to install $pkg" >&2 return 1 fi }
for p in nginx postgresql redis-server; do install_package "$p" || echo "Aborting due to failed installation of $p" && exit 1 done
